      this.baseModelRotation.y = degreesToRadians(this.sceneConfig.modelRotYDeg);
      this.baseModelRotation.z = degreesToRadians(this.sceneConfig.modelRotZDeg);
      this.tokenBaseScale = this.sceneConfig.tokenBaseScale;
